// Build the Gemini generateContent request from the payload the Next.js route
// sends: { fileName, mimeType, data (base64), hints }. We force STRUCTURED JSON
// output (responseSchema) so the reply is always { certification, skills,
// confidence } — exactly what app/api/certificate/analyze/route.ts expects.
const b = $json.body || $json;
const fileName = String(b.fileName || 'certificate');
const mimeType = String(b.mimeType || 'application/pdf');
const data = String(b.data || '');
const hints = String(b.hints || '').slice(0, 500);

// The ONLY skills the app's matcher understands (lib/certificate-ai.ts +
// opportunity roleType/skills). Gemini must pick from this exact vocabulary.
const SKILLS = [
  'First Aid', 'Healthcare Support', 'Hospital Role', 'Counselling',
  'Logistics', 'Logistics Support', 'Teaching', 'Food Handling',
  'Translation', 'Crowd Management', 'General Volunteer'
];

if (!data) { throw new Error('No certificate data in payload'); }

const prompt = [
  'You are analysing a volunteer\u2019s certificate for AidPulse SG, a Singapore',
  'health/disaster volunteering app. Read the attached document.',
  'Filename: "' + fileName + '". User hints: "' + hints + '".',
  '',
  'Return JSON with exactly these fields:',
  '- "certification": the official name of what this document certifies',
  '  (e.g. "Standard First Aid + CPR/AED"). If unclear, use "General certificate".',
  '- "skills": an array chosen ONLY from this exact list: ' + JSON.stringify(SKILLS) + '.',
  '  Include every skill the certificate genuinely supports. If none clearly',
  '  apply, return ["General Volunteer"].',
  '- "confidence": a number from 0 to 1 for how sure you are.'
].join('\n');

const body = {
  contents: [{
    parts: [
      { text: prompt },
      { inline_data: { mime_type: mimeType, data: data } }
    ]
  }],
  generationConfig: {
    temperature: 0.1,
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'OBJECT',
      properties: {
        certification: { type: 'STRING' },
        skills: { type: 'ARRAY', items: { type: 'STRING' } },
        confidence: { type: 'NUMBER' }
      },
      required: ['certification', 'skills', 'confidence']
    }
  }
};

return [{ json: { geminiBody: JSON.stringify(body) } }];

// Gemini returns { candidates: [{ content: { parts: [{ text: '<json>' }] }}]}.
// Extract the JSON text, validate it, and normalise to the exact shape the
// Next.js route returns to the browser: { certification, skills, confidence }.
const SKILLS = [
  'First Aid', 'Healthcare Support', 'Hospital Role', 'Counselling',
  'Logistics', 'Logistics Support', 'Teaching', 'Food Handling',
  'Translation', 'Crowd Management', 'General Volunteer'
];
const allow = new Map(SKILLS.map((s) => [s.toLowerCase(), s]));

let text = '';
try {
  const parts = $json.candidates[0].content.parts || [];
  text = parts.map((p) => p.text || '').join('');
} catch (e) { text = ''; }

let out = { certification: 'General certificate', skills: ['General Volunteer'], confidence: 0.4 };
try {
  const parsed = JSON.parse(text);
  // Keep only recognised skills (case-insensitive), canonicalised to app casing.
  const skills = Array.isArray(parsed.skills)
    ? [...new Set(parsed.skills.map((s) => allow.get(String(s).toLowerCase())).filter(Boolean))]
    : [];
  out = {
    certification: String(parsed.certification || 'General certificate').slice(0, 120),
    skills: skills.length ? skills : ['General Volunteer'],
    confidence: Math.max(0, Math.min(1, Number(parsed.confidence) || 0.5))
  };
} catch (e) { /* keep the safe default */ }

return [{ json: out }];
